import { Link } from "react-router-dom";

function Navbar() {
  return (
    <div className="navbar">

      <Link to="/" className="logo">
        CourseHub
      </Link>

      <input
        className="search"
        placeholder="Что вы хотите изучить?"
      />

      <Link to="/courses">
        Курсы
      </Link>

      <Link to="/login">
        <button className="login-btn">Login</button>
      </Link>

    </div>
  );
}

export default Navbar;
